function.arguments:
{"cmd":"# Configure Nginx for HTTPS on port 8443
cat > /etc/nginx/sites-available/git-deploy << 'NGINX'
server {
    listen 8443 ssl;
    server_name localhost;

    ssl_certificate /etc/ssl/certs/nginx-selfsigned.crt;
    ssl_certificate_key /etc/ssl/private/nginx-selfsigned.key;

    root /var/www/html;

    location / {
        try_files $uri $uri/ =404;
    }
}
NGINX

# Remove default site and enable our config
rm -f /etc/nginx/sites-enabled/default
ln -sf /etc/nginx/sites-available/git-deploy /etc/nginx/sites-enabled/git-deploy

echo "Nginx config created"
cat /etc/nginx/sites-available/git-deploy"}

